KT-20260324-E573	Corrección de datos de liquidación	{"silo": "BBDD", "tipo": "RUN", "orden": 5, "enriched": true, "checklist": ["Conexión a BD establecida", "Registros erróneos identificados", "Backup de datos realizado", "Correcciones aplicadas exitosamente", "Validación de integridad completada", "Commit de transacciones ejecutado"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "Oracle 19c Liquidaciones", "source": "IA"}, {"campo": "Esquema", "valor": "LIQUIDACION_PROD", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "Servidor BD", "valor": "srv-db-liquidacion-01", "source": "IA"}, {"campo": "Tablespace", "valor": "LIQUIDACION_DATA", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a base de datos", "detalle": "Acceder al esquema de liquidaciones", "comandos": ["sqlplus liquidacion_user/password@srv-db-liquidacion-01:1521/PROD"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Identificar registros erróneos", "detalle": "Localizar datos de liquidación con inconsistencias", "comandos": ["SELECT * FROM liquidaciones WHERE estado='ERROR' AND fecha >= TRUNC(SYSDATE-1);", "SELECT liquidacion_id, monto, estado FROM liquidaciones WHERE monto < 0 OR monto IS NULL;"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Realizar backup de datos", "detalle": "Respaldar registros antes de corrección", "comandos": ["CREATE TABLE liquidaciones_backup_$(date +%Y%m%d) AS SELECT * FROM liquidaciones WHERE liquidacion_id IN (lista_ids);"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Ejecutar correcciones", "detalle": "Aplicar las correcciones necesarias en los datos", "comandos": ["UPDATE liquidaciones SET monto = valor_correcto WHERE liquidacion_id = id_especifico;", "UPDATE liquidaciones SET estado = 'PROCESADO' WHERE estado = 'ERROR' AND condicion_correccion;"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Validar correcciones", "detalle": "Verificar que las correcciones se aplicaron correctamente", "comandos": ["SELECT COUNT(*) FROM liquidaciones WHERE estado='ERROR';", "SELECT SUM(monto) FROM liquidaciones WHERE fecha = TRUNC(SYSDATE);"], "source_comandos": "IA"}], "skill_requerida": "SQL: Update", "requiere_negocio": false, "sla_tarea_minutos": 120}	RUN	Alta	Backlog	\N	\N	INC-20260324-C657	\N	2.0	0.0	2026-03-24 22:09:45.862913+00	\N	\N	[]	2026-03-24 22:09:45.862913+00
KT-20260324-0517	Análisis de datos de liquidación con joins	{"silo": "BBDD", "tipo": "RUN", "orden": 4, "enriched": true, "checklist": ["Conexión a BD establecida", "Estructura de tablas analizada", "Consultas con joins ejecutadas", "Performance optimizada", "Reporte de resultados generado", "Documentación de hallazgos completada"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "Oracle 19c Liquidaciones", "source": "IA"}, {"campo": "Esquema principal", "valor": "LIQUIDACION_PROD", "source": "IA"}, {"campo": "Esquema auxiliar", "valor": "COMERCIO_PROD", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "Herramienta", "valor": "SQL Developer / SQLPlus", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a base de datos", "detalle": "Establecer sesión en esquema de liquidaciones", "comandos": ["sqlplus liquidacion_user/password@srv-db-liquidacion-01:1521/PROD"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Analizar estructura de tablas", "detalle": "Revisar relaciones entre tablas de liquidación", "comandos": ["DESC liquidaciones;", "DESC transacciones;", "DESC comercios;", "SELECT table_name FROM user_tables WHERE table_name LIKE '%LIQUID%';"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Ejecutar consulta con joins", "detalle": "Realizar análisis de datos con joins complejos", "comandos": ["SELECT l.liquidacion_id, l.monto, t.tipo_transaccion, c.nombre_comercio FROM liquidaciones l INNER JOIN transacciones t ON l.transaccion_id = t.id INNER JOIN comercios c ON t.comercio_id = c.id WHERE l.fecha >= TRUNC(SYSDATE-7);"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Optimizar consulta", "detalle": "Revisar plan de ejecución y optimizar performance", "comandos": ["EXPLAIN PLAN FOR SELECT...", "SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY);", "CREATE INDEX idx_liquidacion_fecha ON liquidaciones(fecha) TABLESPACE LIQUIDACION_IDX;"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Generar reporte de resultados", "detalle": "Exportar resultados del análisis", "comandos": ["SPOOL /tmp/analisis_liquidacion_$(date +%Y%m%d).txt", "SELECT COUNT(*), SUM(monto), AVG(monto) FROM vista_analisis_liquidacion;", "SPOOL OFF"], "source_comandos": "IA"}], "skill_requerida": "SQL: Inner Join", "requiere_negocio": false, "sla_tarea_minutos": 180}	RUN	Alta	Backlog	\N	\N	INC-20260324-C657	\N	1.5	0.0	2026-03-24 22:09:45.858575+00	\N	\N	[]	2026-03-24 22:09:45.858575+00
KT-20260324-C04E	Consulta estado de remesas en base de datos	{"silo": "BBDD", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Conexión a BD de remesas establecida", "Estado general consultado", "Remesas pendientes identificadas", "Reporte detallado generado", "Inconsistencias documentadas"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Base de datos", "valor": "Oracle 19c Remesas", "source": "IA"}, {"campo": "Esquema", "valor": "REMESAS_PROD", "source": "IA"}, {"campo": "Puerto", "valor": "1521", "source": "IA"}, {"campo": "Servidor BD", "valor": "srv-db-remesas-01", "source": "IA"}, {"campo": "Vista principal", "valor": "V_ESTADO_REMESAS", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Conectar a base de datos de remesas", "detalle": "Acceder al esquema de remesas", "comandos": ["sqlplus remesas_user/password@srv-db-remesas-01:1521/PROD"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Consultar estado general", "detalle": "Revisar estado actual de todas las remesas", "comandos": ["SELECT estado, COUNT(*) FROM remesas GROUP BY estado;", "SELECT * FROM V_ESTADO_REMESAS WHERE fecha >= TRUNC(SYSDATE);"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Identificar remesas pendientes", "detalle": "Localizar remesas en estado pendiente o con errores", "comandos": ["SELECT remesa_id, estado, fecha_creacion, monto FROM remesas WHERE estado IN ('PENDIENTE', 'ERROR') ORDER BY fecha_creacion;"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Generar reporte detallado", "detalle": "Crear reporte con estado de remesas por período", "comandos": ["SELECT TO_CHAR(fecha_creacion, 'YYYY-MM-DD') as fecha, estado, COUNT(*) as cantidad, SUM(monto) as total FROM remesas WHERE fecha_creacion >= TRUNC(SYSDATE-30) GROUP BY TO_CHAR(fecha_creacion, 'YYYY-MM-DD'), estado ORDER BY fecha, estado;"], "source_comandos": "IA"}], "skill_requerida": "SQL: Select Simple", "requiere_negocio": false, "sla_tarea_minutos": 90}	RUN	Alta	Backlog	\N	\N	INC-2026032