KT-20260326-5F6C	Traceroute y análisis de ruta de red	{"silo": "REDES", "tipo": "RUN", "orden": 3, "enriched": true, "checklist": ["Traceroute completado desde ambos controllers", "Rutas a servidores transaccionales mapeadas", "Latencias por hop documentadas", "Pérdidas de paquetes identificadas", "Cuellos de botella en la ruta detectados", "Reporte de rutas generado", "Hallazgos escalados si es necesario"], "area_negocio": "", "contexto_cmdb": {"items": [{"campo": "Origen", "valor": "Controllers ATM (10.0.80.10, 10.0.80.11)", "source": "CMDB"}, {"campo": "Destinos críticos", "valor": "Datacenter principal, Procesador transaccional", "source": "IA"}, {"campo": "Gateway ATM", "valor": "10.0.80.1", "source": "CMDB"}, {"campo": "DNS primario", "valor": "8.8.8.8", "source": "IA"}, {"campo": "Servidor transaccional", "valor": "172.16.10.50", "source": "IA"}, {"campo": "Servidor autorizador", "valor": "172.16.10.51", "source": "IA"}, {"campo": "Herramientas", "valor": "traceroute, mtr, tcptraceroute", "source": "IA"}]}, "instrucciones": [{"paso": 1, "titulo": "Traceroute desde controllers a destinos críticos", "detalle": "Ejecutar trazas de ruta desde cada controller ATM", "comandos": ["ssh root@10.0.80.10", "traceroute -n 172.16.10.50", "traceroute -n 172.16.10.51", "traceroute -n 8.8.8.8"], "source_comandos": "IA"}, {"paso": 2, "titulo": "Análisis MTR para detectar pérdidas", "detalle": "Usar MTR para análisis continuo de la ruta", "comandos": ["mtr -c 20 -r 172.16.10.50", "mtr -c 20 -r 172.16.10.51", "mtr -c 20 -r 10.0.80.1"], "source_comandos": "IA"}, {"paso": 3, "titulo": "Traceroute TCP a puertos específicos", "detalle": "Verificar ruta a nivel de aplicación", "comandos": ["tcptraceroute 172.16.10.50 443", "tcptraceroute 172.16.10.51 8080", "hping3 -T -p 443 -c 5 172.16.10.50"], "source_comandos": "IA"}, {"paso": 4, "titulo": "Análisis de latencia por salto", "detalle": "Medir latencia en cada hop de la ruta", "comandos": ["for i in {1..10}; do ping -c 1 -t $i 172.1