", "ipmitool sensor list | grep -i temp", "ipmitool sensor list | grep -i fan"], "source_comandos": "IA"}, {"paso": 5, "titulo": "Verificar conectividad de red física", "detalle": "Comprobar estado de interfaces de red", "comandos": ["ethtool eth0", "ip link show", "cat /proc/net/bonding/bond0", "mii-tool -v"], "source_comandos": "IA"}, {"paso": 6, "titulo": "Generar reporte de diagnóstico hardware", "detalle": "Documentar hallazgos y estado general del hardware", "comandos": ["dmidecode -t system > /tmp/hw_report.txt", "lshw -short >> /tmp/hw_report.txt"], "source_comandos": "IA"}], "skill_requerida": "Hardware: Diagnóstico Fuente", "requiere_negocio": false, "sla_tarea_minutos": 120}	RUN	Crítica	Backlog	FTE-086	\N	INC-20260326-3E15	\N	0.4	0.0	2026-03-26 11:21:54.636531+00	\N	\N	[]	2026-03-26 11:21:54.636531+00
